var ModeCheck = "check";
async function analyse(vt2, filePath) {
  const uploadUrl = await vt2.getFileUploadURL();
  const result = await vt2.uploadFile(filePath, uploadUrl);
  info(`File "${filePath}" has been submitted for a scan`);
  info(`Analysis URL: ${filehashToGuiUrl(result.filehash)}`);
  return result;
}
async function check2(vt2, commitStatus) {
  const result = await vt2.getFileReport(
    guiUrlToFilehash(commitStatus.target_url)
  );
  info(
    `Current status is "${result.status}" with "${result.flagged}" flags from security vendors`
  );
  return result;
}
async function run() {
  const mode = getInput("mode");
  const virustotalApiKey = getInput("virustotal-api-key", {
    required: true
  });
  const ghToken = getToken();
  const vt2 = new VirusTotal(virustotalApiKey);
  const octokit = getOctokit(ghToken);
  switch (mode) {
    case ModeAnalyse:
      const path = getInput("path", { required: true });
      if (!Debug && !isReleaseBranch()) {
        info(`Skipping: feature branch "${getRef()}" is ignored`);
        return;
      }
      const absPaths = await Ze(path, { absolute: true });
      debug(`Absolute path to file(s): "${absPaths.join(", ")}"`);
      for (const absPath of absPaths) {
        const result = await analyse(vt2, absPath);
        await writeStatus2(octokit, result);
      }
      break;
    case ModeCheck:
      for (const pendingStatus of await getPendingVirusTotalStatuses(octokit)) {
        const result = await check2(vt2, pendingStatus);
        await writeStatus2(octokit, result, pendingStatus.sha);
      }
      break;
    default:
      throw new Error(`Unknown mode "${mode}"`);
  }
}
run().catch(setFailed);
